import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import { AnalysisResult } from "../types";
import { APP_NAME } from "../constants";

export const generateAnalysisPdf = (data: AnalysisResult) => {
  const doc = new jsPDF();
  const pageWidth = doc.internal.pageSize.width;
  const margin = 14;
  let finalY = 0;

  // --- Colori ---
  const primaryColor: [number, number, number] = [37, 99, 235]; // Blue-600
  const secondaryColor: [number, number, number] = [71, 85, 105]; // Slate-600

  // --- Header ---
  doc.setFillColor(primaryColor[0], primaryColor[1], primaryColor[2]);
  doc.rect(0, 0, pageWidth, 20, 'F');

  doc.setTextColor(255, 255, 255);
  doc.setFontSize(16);
  doc.setFont("helvetica", "bold");
  doc.text(APP_NAME, margin, 13);

  doc.setFontSize(10);
  doc.setFont("helvetica", "normal");
  const dateStr = new Date().toLocaleDateString('it-IT', { day: 'numeric', month: 'long', year: 'numeric' });
  doc.text(`Report generato il ${dateStr}`, pageWidth - margin, 13, { align: 'right' });

  // --- Riepilogo Finanziario (Box in alto) ---
  doc.setTextColor(0, 0, 0);
  const summaryTop = 30;

  // Box Netto
  doc.setFillColor(220, 252, 231); // Green-100
  doc.setDrawColor(22, 163, 74); // Green-600
  doc.roundedRect(margin, summaryTop, 60, 25, 2, 2, 'FD');

  doc.setFontSize(10);
  doc.setTextColor(21, 128, 61); // Green-700
  doc.text("NETTO IN BUSTA", margin + 5, summaryTop + 8);
  doc.setFontSize(16);
  doc.setFont("helvetica", "bold");
  doc.text(data.finalSummary.netTotal, margin + 5, summaryTop + 18);

  // Box Lordo
  doc.setFillColor(239, 246, 255); // Blue-50
  doc.setDrawColor(37, 99, 235); // Blue-600
  doc.roundedRect(margin + 65, summaryTop, 55, 25, 2, 2, 'FD');

  doc.setFontSize(10);
  doc.setTextColor(30, 64, 175); // Blue-800
  doc.setFont("helvetica", "normal");
  doc.text("LORDO TOTALE", margin + 70, summaryTop + 8);
  doc.setFontSize(14);
  doc.setFont("helvetica", "bold");
  doc.text(data.finalSummary.grossTotal, margin + 70, summaryTop + 18);

  // Box Trattenute
  doc.setFillColor(254, 242, 242); // Red-50
  doc.setDrawColor(220, 38, 38); // Red-600
  doc.roundedRect(margin + 125, summaryTop, 55, 25, 2, 2, 'FD');

  doc.setFontSize(10);
  doc.setTextColor(153, 27, 27); // Red-800
  doc.setFont("helvetica", "normal");
  doc.text(`TRATTENUTE (${data.calculations.deductionPercentage})`, margin + 130, summaryTop + 8);
  doc.setFontSize(14);
  doc.setFont("helvetica", "bold");
  doc.text(data.calculations.totalDeductions, margin + 130, summaryTop + 18);

  finalY = summaryTop + 35;

  // --- Dati Generali (Tabella) ---
  doc.setFontSize(12);
  doc.setTextColor(secondaryColor[0], secondaryColor[1], secondaryColor[2]);
  doc.setFont("helvetica", "bold");
  doc.text("Dati Generali", margin, finalY);

  const generalDataBody = [
    ["Azienda", data.generalData.employer, "Contratto", data.generalData.contractType],
    ["Dipendente", data.generalData.employee, "CCNL", data.generalData.ccnl],
    ["Periodo", data.generalData.payPeriod, "Livello", data.generalData.level],
  ];

  autoTable(doc, {
    startY: finalY + 3,
    head: [],
    body: generalDataBody,
    theme: 'plain',
    styles: { fontSize: 9, cellPadding: 1.5 },
    columnStyles: {
      0: { fontStyle: 'bold', textColor: secondaryColor, cellWidth: 25 },
      1: { cellWidth: 65 },
      2: { fontStyle: 'bold', textColor: secondaryColor, cellWidth: 25 },
      3: { cellWidth: 'auto' }
    },
  });

  finalY = (doc as any).lastAutoTable.finalY + 10;

  // --- Ferie & ROL Analysis ---
  doc.setFontSize(12);
  doc.setTextColor(secondaryColor[0], secondaryColor[1], secondaryColor[2]);
  doc.setFont("helvetica", "bold");
  doc.text("Ferie & Permessi", margin, finalY);

  const leaveBody = [
    [
      "FERIE", 
      data.leaveAnalysis.vacation.unit,
      data.leaveAnalysis.vacation.previousBalance, 
      data.leaveAnalysis.vacation.accrued, 
      data.leaveAnalysis.vacation.taken, 
      data.leaveAnalysis.vacation.balance
    ],
    [
      "R.O.L. / EX-FEST", 
      data.leaveAnalysis.rol.unit,
      data.leaveAnalysis.rol.previousBalance, 
      data.leaveAnalysis.rol.accrued, 
      data.leaveAnalysis.rol.taken, 
      data.leaveAnalysis.rol.balance
    ]
  ];

  autoTable(doc, {
    startY: finalY + 3,
    head: [['Tipologia', 'Unità', 'Residuo Prec.', 'Maturato', 'Goduto', 'Saldo Finale']],
    body: leaveBody,
    theme: 'striped',
    headStyles: { fillColor: secondaryColor, textColor: 255, fontStyle: 'bold' },
    styles: { fontSize: 9, cellPadding: 2, halign: 'center' },
    columnStyles: {
      0: { halign: 'left', fontStyle: 'bold' }
    }
  });

  finalY = (doc as any).lastAutoTable.finalY + 5;

  // Nota dell'esperto (Ferie)
  if (data.leaveAnalysis.humanExplanation) {
      doc.setFontSize(9);
      doc.setFont("helvetica", "italic");
      doc.setTextColor(100);
      const splitNote = doc.splitTextToSize(`Nota: ${data.leaveAnalysis.humanExplanation}`, pageWidth - (margin * 2));
      doc.text(splitNote, margin, finalY + 3);
      finalY += (splitNote.length * 4) + 8;
  } else {
      finalY += 5;
  }

  // --- Spiegazione Semplice ---
  doc.setFontSize(12);
  doc.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
  doc.setFont("helvetica", "bold");
  doc.text("In parole semplici", margin, finalY);

  doc.setFontSize(10);
  doc.setTextColor(0, 0, 0);
  doc.setFont("helvetica", "normal");

  const splitSummary = doc.splitTextToSize(data.simpleExplanation.summary, pageWidth - (margin * 2));
  doc.text(splitSummary, margin, finalY + 6);

  const summaryHeight = splitSummary.length * 4;
  finalY += 10 + summaryHeight;

  // Punti chiave
  data.simpleExplanation.keyTakeaways.forEach((point) => {
      // Check page break
      if (finalY > 270) {
        doc.addPage();
        finalY = 20;
      }
      doc.setFillColor(primaryColor[0], primaryColor[1], primaryColor[2]);
      doc.circle(margin + 2, finalY - 1, 1, 'F');
      const splitPoint = doc.splitTextToSize(point, pageWidth - (margin * 2) - 5);
      doc.text(splitPoint, margin + 5, finalY);
      finalY += (splitPoint.length * 4) + 2;
  });

  finalY += 8;

  // --- Tabella Dettaglio Voci ---
  if (finalY > 240) {
      doc.addPage();
      finalY = 20;
  }

  doc.setFontSize(12);
  doc.setTextColor(secondaryColor[0], secondaryColor[1], secondaryColor[2]);
  doc.setFont("helvetica", "bold");
  doc.text("Dettaglio Voci", margin, finalY);

  const tableBody = data.lineItems.map(item => [
    item.name,
    item.category,
    item.amount,
    `Cos'è: ${item.explanation.whatIsIt}\nChi paga: ${item.explanation.whoPays}\nNote: ${item.explanation.notes}`
  ]);

  autoTable(doc, {
    startY: finalY + 3,
    head: [['Voce', 'Categoria', 'Importo', 'Dettagli']],
    body: tableBody,
    theme: 'grid',
    headStyles: { fillColor: primaryColor, textColor: 255, fontStyle: 'bold' },
    styles: { fontSize: 9, cellPadding: 3, valign: 'top' },
    columnStyles: {
      0: { cellWidth: 40, fontStyle: 'bold' },
      1: { cellWidth: 30, fontSize: 8, fontStyle: 'italic' },
      2: { cellWidth: 25, halign: 'right', fontStyle: 'bold' },
      3: { cellWidth: 'auto' } // Colonna dettagli flessibile
    },
    didParseCell: function(data) {
        if (data.section === 'body' && data.column.index === 1) {
            const cat = data.cell.raw as string;
            if (cat.toLowerCase().includes('trattenute') || cat.toLowerCase().includes('imposte')) {
                data.cell.styles.textColor = [220, 38, 38] as [number, number, number];
            } else if (cat.toLowerCase().includes('retribuzione')) {
                data.cell.styles.textColor = [22, 163, 74] as [number, number, number];
            }
        }
    }
  });

  finalY = (doc as any).lastAutoTable.finalY + 15;

  // --- Verifiche & Anomalie (NUOVA SEZIONE) ---
  const activeChecks = data.consistencyChecks.filter(c => !(c.isConsistent && c.severity === 'info'));

  if (activeChecks.length > 0) {
      if (finalY > 240) {
          doc.addPage();
          finalY = 20;
      }

      doc.setFontSize(12);
      doc.setTextColor(secondaryColor[0], secondaryColor[1], secondaryColor[2]);
      doc.setFont("helvetica", "bold");
      doc.text("Verifiche & Anomalie", margin, finalY);

      finalY += 5;

      activeChecks.forEach(check => {
          let boxColor: [number, number, number] = [239, 246, 255]; // Default Blue
          let borderColor: [number, number, number] = [191, 219, 254];
          let textColor: [number, number, number] = [30, 58, 138];
          let title = "INFO";

          if (check.severity === 'error') {
              boxColor = [254, 242, 242]; // Red-50
              borderColor = [252, 165, 165]; // Red-300
              textColor = [153, 27, 27]; // Red-800
              title = "ATTENZIONE";
          } else if (check.severity === 'warning') {
              boxColor = [255, 251, 235]; // Amber-50
              borderColor = [252, 211, 77]; // Amber-300
              textColor = [146, 64, 14]; // Amber-800
              title = "ATTENZIONE";
          } else {
             title = "NOTA";
          }

          doc.setFillColor(boxColor[0], boxColor[1], boxColor[2]);
          doc.setDrawColor(borderColor[0], borderColor[1], borderColor[2]);

          // Calcolo altezza dinamica
          doc.setFontSize(10);
          doc.setFont("helvetica", "bold");
          const titleWidth = doc.getTextWidth(title);

          doc.setFont("helvetica", "normal");
          const splitMsg = doc.splitTextToSize(check.message, pageWidth - (margin * 2) - 10);
          const boxHeight = 10 + (splitMsg.length * 5); // padding top/bottom + text lines

          // Check page break inside loop
          if (finalY + boxHeight > 280) {
             doc.addPage();
             finalY = 20;
          }

          doc.roundedRect(margin, finalY, pageWidth - (margin * 2), boxHeight, 2, 2, 'FD');

          doc.setTextColor(textColor[0], textColor[1], textColor[2]);
          doc.setFont("helvetica", "bold");
          doc.text(title, margin + 5, finalY + 7);

          doc.setFont("helvetica", "normal");
          doc.text(splitMsg, margin + 5, finalY + 13);

          finalY += boxHeight + 5;
      });
  }

  doc.save(`${APP_NAME.replace(/\s+/g, '_')}_Analisi.pdf`);
};

export interface GeneralData {
  employer: string;
  employee: string;
  payPeriod: string;
  contractType: string;
  ccnl: string;
  level: string;
}

export interface LineItemExplanation {
  whatIsIt: string;
  whyItExists: string;
  whoPays: string;
  impact: {
    gross: boolean;
    net: boolean;
    tfr: boolean;
  };
  notes: string;
}

export interface LineItem {
  name: string;
  category: string; // e.g., "Retribuzione base", "Imposte", etc.
  amount: string; // Keeping as string to preserve original formatting, or parse as number
  explanation: LineItemExplanation;
}

export interface Calculations {
  grossHourlyRate: string;
  netHourlyRateEstimated: string;
  totalDeductions: string;
  deductionPercentage: string;
}

export interface ConsistencyCheck {
  isConsistent: boolean;
  message: string;
  severity: 'info' | 'warning' | 'error';
  scientificExplanation?: string; // Nuova spiegazione tecnica
}

export interface SimpleExplanation {
  summary: string;
  keyTakeaways: string[];
}

// Nuova interfaccia per il dettaglio di una singola tipologia di assenza
export interface LeaveDetails {
  unit: string; // "Ore" o "Giorni"
  previousBalance: string; // Residuo Anno Precedente
  accrued: string; // Maturato Anno Corrente/Mese
  taken: string; // Goduto
  balance: string; // Residuo Finale
  isConsistent: boolean; // True se Precedente + Maturato - Goduto ~= Saldo
  note: string; // Spiegazione tecnica su eventuali anomalie
}

// Nuova interfaccia contenitore per l'analisi Ferie/ROL
export interface LeaveAnalysis {
  vacation: LeaveDetails; // Ferie
  rol: LeaveDetails; // ROL / Permessi / Ex-Festività aggregati
  humanExplanation: string; // Spiegazione semplice per l'utente ("Hai consumato 2 giorni...")
}

export interface AnalysisResult {
  generalData: GeneralData;
  lineItems: LineItem[];
  calculations: Calculations;
  leaveAnalysis: LeaveAnalysis; // Aggiunto qui
  consistencyChecks: ConsistencyCheck[];
  simpleExplanation: SimpleExplanation;
  finalSummary: {
    netTotal: string;
    grossTotal: string;
    topImpactItems: string[];
    improvementTips: string;
  };
}

export type AnalysisStatus = 'idle' | 'extracting' | 'analyzing' | 'success' | 'error';

import { Schema, Type } from "@google/genai";

export const APP_NAME = "Busta Paga Expert";

export const PAYSLIP_ANALYSIS_PROMPT = `
Agisci come Esperto Senior in Paghe e Contributi (Consulenza del lavoro, CCNL italiani).
Analizza il testo estratto da una busta paga digitale italiana.

Obiettivo: Analisi retributiva completa con focus specifico su FERIE e R.O.L./Permessi.

Segui rigorosamente queste fasi:

Fase 1: Parsing Dati Generali
Estrai: Datore, Dipendente, Periodo, Contratto (Full/Part-time), CCNL, Livello.

Fase 2: Analisi FERIE e R.O.L. (MOTORE DI CALCOLO OBBLIGATORIO)
Devi estrarre e verificare matematicamente i contatori.
Input attesi dal testo: Residuo Anno Precedente (AP), Maturato Anno Corrente/Mese, Goduto, Saldo.

LOGICA DI CALCOLO:
1. Maturazione:
   - Se possibile, stima il maturato atteso: (Ferie Annue CCNL / 12) * % Part-time.
   - Confronta con il valore "Maturato" in busta.
2. Godimento:
   - Cerca voci nel corpo del cedolino come "Ferie Godute", "Permessi Goduti", "Assenza Retribuita".
   - Verifica se le ore godute nei contatori corrispondono alle ore trattenute/pagate nel cedolino.
   - Segnala se risultano ferie scalate (Goduto > 0) ma nessuna voce corrispondente nel cedolino.
3. Residuo (Balance):
   - Formula: Residuo Attuale = Residuo Precedente + Maturato - Goduto.
   - Se il testo riporta un Saldo diverso dal tuo calcolo, segnala l'anomalia.

OUTPUT RICHIESTO PER QUESTA FASE:
Compila i campi "vacation" (Ferie) e "rol" (Permessi/Ex-Festività aggregati).
- unit: "Ore" o "Giorni" (cerca di capire l'unità di misura).
- isConsistent: false se la matematica non torna o se ferie scalate non compaiono in busta.
- note: Spiegazione tecnica (es: "Maturazione inferiore al previsto per part-time", "Saldo matematicamente non corretto: atteso X, trovato Y").

Fase 3: Riconoscimento Voci del cedolino
Classifica ogni riga (Retribuzione, Straordinari, Trattenute, etc.).

Fase 4: Spiegazione Voce per Voce
Spiega cos'è, perché esiste, chi paga.

Fase 5: Verifiche Coerenza (Cross-Check) e Spiegazione Scientifica
- Controlla se le assenze (Malattia, Infortunio) influenzano la maturazione ferie.
- Controlla se il netto è coerente con lordo e trattenute.
IMPORTANTE: Se rilevi una discrepanza (Warning/Error), DEVI compilare il campo "scientificExplanation".
In questo campo, agisci come un revisore contabile che spiega il PERCHÉ tecnico del disallineamento, evitando allarmismi.
Esempi di cause tecniche da citare:
- Arrotondamenti del software paghe (comuni fino a qualche euro).
- Voci figurative non monetarie che alterano il lordo ma non il netto.
- Trattamento fiscale separato del TFR o arretrati anni precedenti.
- Addizionali regionali/comunali a saldo (spesso causano disallineamenti apparenti).
- Conguagli di fine anno o fine rapporto.
Il tono deve essere: "Non preoccuparti, è probabilmente dovuto a X".

Fase 6: Spiegazione Umana (Leave Analysis)
Scrivi un riassunto specifico per Ferie/ROL: "Hai consumato 2 giorni di ferie, te ne restano 10. La maturazione è regolare."

Output Finale: Restituisci SOLO un JSON strutturato secondo lo schema fornito.
`;

