      required: ["netTotal", "grossTotal", "topImpactItems", "improvementTips"],
    },
  },
  required: ["generalData", "leaveAnalysis", "lineItems", "calculations", "consistencyChecks", "simpleExplanation", "finalSummary"],
};

import React from 'react';
import { ConsistencyCheck } from '../types';
import { AlertTriangle, Info, BookOpen } from 'lucide-react';

interface Props {
  checks: ConsistencyCheck[];
}

const ConsistencyChecks: React.FC<Props> = ({ checks }) => {
  if (!checks || checks.length === 0) return null;

  const hasIssues = checks.some(c => !c.isConsistent);

  if (!hasIssues) return null;

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 mb-6">
        <h2 className="text-lg font-bold text-slate-800 mb-4">Verifiche & Anomalie</h2>
        <div className="space-y-4">
            {checks.map((check, idx) => {
                if (check.isConsistent && check.severity === 'info') return null; // Skip "all good" redundant info

                return (
                    <div key={idx} className={`p-4 rounded-lg border ${
                        check.severity === 'error' ? 'bg-red-50 border-red-100 text-red-900' :
                        check.severity === 'warning' ? 'bg-amber-50 border-amber-100 text-amber-900' :
                        'bg-blue-50 border-blue-100 text-blue-900'
                    }`}>
                        <div className="flex items-start gap-3 mb-2">
                            {check.severity === 'error' && <AlertTriangle className="w-5 h-5 shrink-0 text-red-600" />}
                            {check.severity === 'warning' && <AlertTriangle className="w-5 h-5 shrink-0 text-amber-600" />}
                            {check.severity === 'info' && <Info className="w-5 h-5 shrink-0 text-blue-600" />}

                            <div>
                                <p className="font-bold text-sm mb-1">
                                    {check.isConsistent ? 'Info' : 'Attenzione'}
                                </p>
                                <p className="text-sm leading-relaxed">{check.message}</p>
                            </div>
                        </div>

                        {check.scientificExplanation && (
                            <div className="mt-3 pl-8">
                                <div className={`text-xs p-3 rounded-md border flex items-start gap-2 ${
                                    check.severity === 'error' ? 'bg-red-100/50 border-red-200 text-red-800' :
                                    check.severity === 'warning' ? 'bg-amber-100/50 border-amber-200 text-amber-800' :
                                    'bg-blue-100/50 border-blue-200 text-blue-800'
                                }`}>
                                    <BookOpen className="w-4 h-4 shrink-0 mt-0.5 opacity-70" />
                                    <div>
                                        <span className="font-semibold block mb-0.5">Spiegazione Tecnica:</span>
                                        <p className="opacity-90 leading-relaxed">{check.scientificExplanation}</p>
                                    </div>
                                </div>
                            </div>
                        )}
                    </div>
                )
            })}
        </div>
    </div>
  );
};

export default ConsistencyChecks;

import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import { AnalysisResult } from "../types";
import { APP_NAME } from "../constants";

export const generateAnalysisPdf = (data: AnalysisResult) => {
  const doc = new jsPDF();
  const pageWidth = doc.internal.pageSize.width;
  const margin = 14;
  let finalY = 0;

  // --- Colori ---
  const primaryColor: [number, number, number] = [37, 99, 235]; // Blue-600
  const secondaryColor: [number, number, number] = [71, 85, 105]; // Slate-600

  // --- Header ---
  doc.setFillColor(primaryColor[0], primaryColor[1], primaryColor[2]);
  doc.rect(0, 0, pageWidth, 20, 'F');

  doc.setTextColor(255, 255, 255);
  doc.setFontSize(16);
  doc.setFont("helvetica", "bold");
  doc.text(APP_NAME, margin, 13);

  doc.setFontSize(10);
  doc.setFont("helvetica", "normal");
  const dateStr = new Date().toLocaleDateString('it-IT', { day: 'numeric', month: 'long', year: 'numeric' });
  doc.text(`Report generato il ${dateStr}`, pageWidth - margin, 13, { align: 'right' });

  // --- Riepilogo Finanziario (Box in alto) ---
  doc.setTextColor(0, 0, 0);
  const summaryTop = 30;

  // Box Netto
  doc.setFillColor(220, 252, 231); // Green-100
  doc.setDrawColor(22, 163, 74); // Green-600
  doc.roundedRect(margin, summaryTop, 60, 25, 2, 2, 'FD');

  doc.setFontSize(10);
  doc.setTextColor(21, 128, 61); // Green-700
  doc.text("NETTO IN BUSTA", margin + 5, summaryTop + 8);
  doc.setFontSize(16);
  doc.setFont("helvetica", "bold");
  doc.text(data.finalSummary.netTotal, margin + 5, summaryTop + 18);

  // Box Lordo
  doc.setFillColor(239, 246, 255); // Blue-50
  doc.setDrawColor(37, 99, 235); // Blue-600
  doc.roundedRect(margin + 65, summaryTop, 55, 25, 2, 2, 'FD');

  doc.setFontSize(10);
  doc.setTextColor(30, 64, 175); // Blue-800
  doc.setFont("helvetica", "normal");
  doc.text("LORDO TOTALE", margin + 70, summaryTop + 8);
  doc.setFontSize(14);
  doc.setFont("helvetica", "bold");
  doc.text(data.finalSummary.grossTotal, margin + 70, summaryTop + 18);

  // Box Trattenute
  doc.setFillColor(254, 242, 242); // Red-50
  doc.setDrawColor(220, 38, 38); // Red-600
  doc.roundedRect(margin + 125, summaryTop, 55, 25, 2, 2, 'FD');

  doc.setFontSize(10);
  doc.setTextColor(153, 27, 27); // Red-800
  doc.setFont("helvetica", "normal");
  doc.text(`TRATTENUTE (${data.calculations.deductionPercentage})`, margin + 130, summaryTop + 8);
  doc.setFontSize(14);
  doc.setFont("helvetica", "bold");
  doc.text(data.calculations.totalDeductions, margin + 130, summaryTop + 18);

  finalY = summaryTop + 35;

  // --- Dati Generali (Tabella) ---
  doc.setFontSize(12);
  doc.setTextColor(secondaryColor[0], secondaryColor[1], secondaryColor[2]);
  doc.setFont("helvetica", "bold");
  doc.text("Dati Generali", margin, finalY);

  const generalDataBody = [
    ["Azienda", data.generalData.employer, "Contratto", data.generalData.contractType],
    ["Dipendente", data.generalData.employee, "CCNL", data.generalData.ccnl],
    ["Periodo", data.generalData.payPeriod, "Livello", data.generalData.level],
  ];

  autoTable(doc, {
    startY: finalY + 3,
    head: [],
    body: generalDataBody,
    theme: 'plain',
    styles: { fontSize: 9, cellPadding: 1.5 },
    columnStyles: {
      0: { fontStyle: 'bold', textColor: secondaryColor, cellWidth: 25 },
      1: { cellWidth: 65 },
      2: { fontStyle: 'bold', textColor: secondaryColor, cellWidth: 25 },
      3: { cellWidth: 'auto' }
    },
  });

  finalY = (doc as any).lastAutoTable.finalY + 10;

  // --- Ferie & ROL Analysis ---
  doc.setFontSize(12);
  doc.setTextColor(secondaryColor[0], secondaryColor[1], secondaryColor[2]);
  doc.setFont("helvetica", "bold");
  doc.text("Ferie & Permessi", margin, finalY);

  const leaveBody = [
    [
      "FERIE", 
      data.leaveAnalysis.vacation.unit,
      data.leaveAnalysis.vacation.previousBalance, 
      data.leaveAnalysis.vacation.accrued, 
      data.leaveAnalysis.vacation.taken, 
      data.leaveAnalysis.vacation.balance
    ],
    [
      "R.O.L. / EX-FEST", 
      data.leaveAnalysis.rol.unit,
      data.leaveAnalysis.rol.previousBalance, 
      data.leaveAnalysis.rol.accrued, 
      data.leaveAnalysis.rol.taken, 
      data.leaveAnalysis.rol.balance
    ]
  ];

  autoTable(doc, {
    startY: finalY + 3,
    head: [['Tipologia', 'Unità', 'Residuo Prec.', 'Maturato', 'Goduto', 'Saldo Finale']],
    body: leaveBody,
    theme: 'striped',
    headStyles: { fillColor: secondaryColor, textColor: 255, fontStyle: 'bold' },
    styles: { fontSize: 9, cellPadding: 2, halign: 'center' },
    columnStyles: {
      0: { halign: 'left', fontStyle: 'bold' }
    }
  });

  finalY = (doc as any).lastAutoTable.finalY + 5;

  // Nota dell'esperto (Ferie)
  if (data.leaveAnalysis.humanExplanation) {
      doc.setFontSize(9);
      doc.setFont("helvetica", "italic");
      doc.setTextColor(100);
      const splitNote = doc.splitTextToSize(`Nota: ${data.leaveAnalysis.humanExplanation}`, pageWidth - (margin * 2));
      doc.text(splitNote, margin, finalY + 3);
      finalY += (splitNote.length * 4) + 8;
  } else {
      finalY += 5;
  }

  // --- Spiegazione Semplice ---
  doc.setFontSize(12);
  doc.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
  doc.setFont("helvetica", "bold");
  doc.text("In parole semplici", margin, finalY);

  doc.setFontSize(10);
  doc.setTextColor(0, 0, 0);
  doc.setFont("helvetica", "normal");

  const splitSummary = doc.splitTextToSize(data.simpleExplanation.summary, pageWidth - (margin * 2));
  doc.text(splitSummary, margin, finalY + 6);

  const summaryHeight = splitSummary.length * 4;
  finalY += 10 + summaryHeight;

  // Punti chiave
  data.simpleExplanation.keyTakeaways.forEach((point) => {
      // Check page break
      if (finalY > 270) {
        doc.addPage();
        finalY = 20;
      }
      doc.setFillColor(primaryColor[0], primaryColor[1], primaryColor[2]);
      doc.circle(margin + 2, finalY - 1, 1, 'F');
      const splitPoint = doc.splitTextToSize(point, pageWidth - (margin * 2) - 5);
      doc.text(splitPoint, margin + 5, finalY);
      finalY += (splitPoint.length * 4) + 2;
  });

  finalY += 8;

  // --- Tabella Dettaglio Voci ---
  if (finalY > 240) {
      doc.addPage();
      finalY = 20;
  }

  doc.setFontSize(12);
  doc.setTextColor(secondaryColor[0], secondaryColor[1], secondaryColor[2]);
  doc.setFont("helvetica", "bold");
  doc.text("Dettaglio Voci", margin, finalY);

  const tableBody = data.lineItems.map(item => [
    item.name,
    item.category,
    item.amount,
    `Cos'è: ${item.explanation.whatIsIt}\nChi paga: ${item.explanation.whoPays}\nNote: ${item.explanation.notes}`
  ]);

  autoTable(doc, {
    startY: finalY + 3,
    head: [['Voce', 'Categoria', 'Importo', 'Dettagli']],
    body: tableBody,
    theme: 'grid',
    headStyles: { fillColor: primaryColor, textColor: 255, fontStyle: 'bold' },
    styles: { fontSize: 9, cellPadding: 3, valign: 'top' },
    columnStyles: {
      0: { cellWidth: 40, fontStyle: 'bold' },
      1: { cellWidth: 30, fontSize: 8, fontStyle: 'italic' },
      2: { cellWidth: 25, halign: 'right', fontStyle: 'bold' },
      3: { cellWidth: 'auto' } // Colonna dettagli flessibile
    },
    didParseCell: function(data) {
        if (data.section === 'body' && data.column.index === 1) {
            const cat = data.cell.raw as string;
            if (cat.toLowerCase().includes('trattenute') || cat.toLowerCase().includes('imposte')) {
                data.cell.styles.textColor = [220, 38, 38] as [number, number, number];
            } else if (cat.toLowerCase().includes('retribuzione')) {
                data.cell.styles.textColor = [22, 163, 74] as [number, number, number];
            }
        }
    }
  });

  finalY = (doc as any).lastAutoTable.finalY + 15;

  // --- Verifiche & Anomalie (NUOVA SEZIONE) ---
  const activeChecks = data.consistencyChecks.filter(c => !(c.isConsistent && c.severity === 'info'));

  if (activeChecks.length > 0) {
      if (finalY > 240) {
          doc.addPage();
          finalY = 20;
      }

      doc.setFontSize(12);
      doc.setTextColor(secondaryColor[0], secondaryColor[1], secondaryColor[2]);
      doc.setFont("helvetica", "bold");
      doc.text("Verifiche & Anomalie", margin, finalY);

      finalY += 5;

      activeChecks.forEach(check => {
          let boxColor: [number, number, number] = [239, 246, 255]; // Default Blue
          let borderColor: [number, number, number] = [191, 219, 254];
          let textColor: [number, number, number] = [30, 58, 138];
          let title = "INFO";

          if (check.severity === 'error') {
              boxColor = [254, 242, 242]; // Red-50
              borderColor = [252, 165, 165]; // Red-300
              textColor = [153, 27, 27]; // Red-800
              title = "ATTENZIONE";
          } else if (check.severity === 'warning') {
              boxColor = [255, 251, 235]; // Amber-50
              borderColor = [252, 211, 77]; // Amber-300
              textColor = [146, 64, 14]; // Amber-800
              title = "ATTENZIONE";
          } else {
             title = "NOTA";
          }

          doc.setFillColor(boxColor[0], boxColor[1], boxColor[2]);
          doc.setDrawColor(borderColor[0], borderColor[1], borderColor[2]);

          // 1. Calcolo altezza messaggio principale
          doc.setFontSize(10);
          doc.setFont("helvetica", "normal");
          const splitMsg = doc.splitTextToSize(check.message, pageWidth - (margin * 2) - 10);
          let boxHeight = 10 + (splitMsg.length * 5); // padding top/bottom + text lines

          // 2. Calcolo altezza Spiegazione Scientifica (se presente)
          let splitExplanation: string[] = [];
          if (check.scientificExplanation) {
             splitExplanation = doc.splitTextToSize(`Analisi Tecnica: ${check.scientificExplanation}`, pageWidth - (margin * 2) - 15);
             boxHeight += (splitExplanation.length * 4) + 5; // Aggiunge spazio extra
          }

          // Check page break inside loop
          if (finalY + boxHeight > 280) {
             doc.addPage();
             finalY = 20;
          }

          // Disegna Box Contenitore
          doc.roundedRect(margin, finalY, pageWidth - (margin * 2), boxHeight, 2, 2, 'FD');

          // Titolo Box
          doc.setTextColor(textColor[0], textColor[1], textColor[2]);
          doc.setFont("helvetica", "bold");
          doc.text(title, margin + 5, finalY + 7);

          // Messaggio Principale
          doc.setFont("helvetica", "normal");
          doc.text(splitMsg, margin + 5, finalY + 13);

          // Spiegazione Scientifica (sub-section)
          if (check.scientificExplanation && splitExplanation.length > 0) {
              const explanationY = finalY + 13 + (splitMsg.length * 5) + 2;
              doc.setFont("helvetica", "italic");
              doc.setFontSize(9);
              // Leggermente più scuro/diverso per distinguere
              doc.setTextColor(textColor[0], textColor[1], textColor[2]); 
              doc.text(splitExplanation, margin + 8, explanationY);
          }

          finalY += boxHeight + 5;
      });
  }

  doc.save(`${APP_NAME.replace(/\s+/g, '_')}_Analisi.pdf`);
};
